import { tick } from 'svelte';
import { test } from '../../test';

export default test({
  html: `
    <button>reset</button>
    <button>hello</button>
    <p>pending</p>
  `,

  async test({ assert, target }) {
    const [reset, hello] = target.querySelectorAll('button');

    hello.click();
    await tick();
    assert.htmlEqual(
      target.innerHTML,
      `<button>reset</button><button>hello</button><p>hello</p>`
    );
  }
});

