import 'svelte/internal/disclose-version';
import 'svelte/internal/flags/async';
import * as $ from 'svelte/internal/client';

var root_1 = $.from_html(`<p> </p>`);
var on_click = (_, promise) => $.set(promise, Promise.resolve("world"), true);
var root = $.from_html(`<button>update</button><!>`, 1);

export default function _unknown_($$anchor) {
        const child = async ($$anchor) => {
                $.async_body(async () => {
                        const value = (await $.save($.async_derived(() => $.get(promise))))();

                        if ($.aborted()) return;

                        var p = root_1();
                        var text = $.child(p, true);

                        $.reset(p);
                        $.template_effect(() => $.set_text(text, $.get(value)));
                        $.append($$anchor, p);
                });
        };

        let promise = $.state($.proxy(Promise.resolve("hello")));
        var fragment = root();
        var button = $.first_child(fragment);

        button.__click = [on_click, promise];

        var node = $.sibling(button);

        child(node);
        $.append($$anchor, fragment);
}

$.delegate(['click']);

