// After:
if (has_await) {
    return b.block([b.stmt(b.call('$.async_body', b.arrow([], b.block(body), true)))]);
} else {
    return b.block(body);
}
```

The old code would push `var $$unsuspend = $.suspend()` FIRST, then `state.consts`, then the aborted check, then `state.init`, then `state.update`, and finally `$$unsuspend()`.

The new code wraps everything in `async_body(() => { ... })`. The `async_body` function does:
```js
export async function async_body(fn) {
    const unsuspend = suspend();
    const active = active_effect;
    try {
        await fn();
    } catch (error) {
        if (!aborted(active)) {
            invoke_error_boundary(error, active);
        }
    } finally {
        unsuspend();
    }
}
```

