import 'svelte/internal/disclose-version';
import 'svelte/internal/flags/async';
import * as $ from 'svelte/internal/client';

var root_1 = $.from_html(`<p>pending</p>`);
var root_3 = $.from_html(`<p> </p>`);

export default function _unknown_($$anchor) {
        let deferred = $.proxy(Promise.withResolvers());
        var fragment = $.comment();
        var node = $.first_child(fragment);

        {
                const pending = ($$anchor) => {
                        var p = root_1();

                        $.append($$anchor, p);
                };

                $.boundary(node, { pending }, ($$anchor) => {
                        $.async_body(async () => {
                                const value = (await $.save($.async_derived(() => deferred.promise)))();

                                if ($.aborted()) return;

                                const child = ($$anchor) => {
                                        var p_1 = root_3();
                                        var text = $.child(p_1, true);

                                        $.reset(p_1);
                                        $.template_effect(() => $.set_text(text, $.get(value)));
                                        $.append($$anchor, p_1);
                                };

                                child($$anchor);
                        });
                });
        }

        $.append($$anchor, fragment);
}

